import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, Tag, Eye
} from 'lucide-react';

// --- ESTILOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem', background: '#f8fafc', borderBottom: '1px solid #e2e8f0' };
const tdCell = { padding: '10px', borderBottom: '1px solid #f1f5f9' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', background: 'transparent', fontSize: '0.9rem' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  const filaNueva = () => ({
    id: Date.now() + Math.random(),
    producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null
  });

  const [filas, setFilas] = useState([filaNueva()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);

  // Memorizamos la función para que useEffect no se queje de la dependencia
  const cargarPublicados = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) {
      console.error("Error cargando publicados", e);
    }
  }, [API_URL, localId]);

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`)
      .then(res => setGaleria(res.data))
      .catch(err => console.log("Error galeria", err));
  }, [cargarPublicados]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    const nuevas = lineas.map(line => {
        const celdas = line.split('\t');
        const nombre = celdas[0] || '';
        return { 
          ...filaNueva(), 
          id: Math.random(), 
          producto: nombre, 
          precioNuevo: celdas[1] || '', 
          precioViejo: celdas[2] || '', 
          stock: celdas[3] || 0, 
          categoria: celdas[4] || 'Almacén', 
          fotoSugerida: buscarMatch(nombre) 
        };
    });
    setFilas(nuevas);
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Por favor, selecciona fecha de inicio y fin.");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          categoria: f.categoria,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Productos publicados en la nube!");
      setFilas([filaNueva()]);
      cargarPublicados(); 
    } catch (e) { 
      alert("Error al publicar."); 
    } finally { 
      setCargando(false); 
    }
  };

  const eliminarOferta = async (id) => {
    if(!window.confirm("¿Deseas eliminar esta publicación?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarPublicados();
    } catch (e) { alert("Error al eliminar"); }
  };

  return (
    <div style={containerStyle}>
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Dashboard</button>
        <button style={{...btnNuevaSucursalCustom, background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22'}}>
          <Database size={16}/> Biblioteca Maestra
        </button>
      </div>

      <div style={{marginBottom: '30px'}}>
        <h1 style={sidebarTitle}><Tag color="#e67e22"/> Editor de Inventario</h1>
        <p style={{color: '#64748b', marginTop: '5px'}}>Pegá tus celdas de Excel para actualizar precios y stock masivamente.</p>
      </div>

      <div style={tableWrapper} onPaste={handlePaste}>
        <table style={mainTable}>
           <thead>
             <tr>
               <th style={thCell}>Foto</th>
               <th style={thCell}>Producto</th>
               <th style={thCell}>P. Nuevo</th>
               <th style={thCell}>P. Viejo</th>
               <th style={thCell}>Stock</th>
               <th style={thCell}>Acción</th>
             </tr>
           </thead>
           <tbody>
             {filas.map(f => (
               <tr key={f.id}>
                 <td style={tdCell}>
                    {f.fotoSugerida ? 
                      <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_50,h_50,c_fill/v1/${f.fotoSugerida.publicId}`} style={{borderRadius:'8px'}} alt="preview"/> 
                      : <ImageIcon color="#cbd5e1" size={24}/>
                    }
                 </td>
                 <td style={tdCell}>
                    <input style={inputTable} placeholder="Nombre..." value={f.producto} onChange={e => {
                        const n = [...filas];
                        const idx = n.findIndex(x => x.id === f.id);
                        n[idx].producto = e.target.value;
                        n[idx].fotoSugerida = buscarMatch(e.target.value);
                        setFilas(n);
                    }}/>
                 </td>
                 <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioNuevo} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].precioNuevo = e.target.value; setFilas(n);}}/></td>
                 <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.precioViejo} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].precioViejo = e.target.value; setFilas(n);}}/></td>
                 <td style={tdCell}><input style={inputTable} type="number" placeholder="0" value={f.stock} onChange={e => {const n = [...filas]; n[n.findIndex(x => x.id === f.id)].stock = e.target.value; setFilas(n);}}/></td>
                 <td style={tdCell}>
                    <button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={{border:'none', background:'none', color:'#cbd5e1', cursor:'pointer'}}><Plus style={{transform:'rotate(45deg)'}} size={18}/></button>
                 </td>
               </tr>
             ))}
           </tbody>
        </table>
        <div style={{padding: '20px', background: '#f8fafc', borderTop: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
            <div style={{display:'flex', gap:'15px'}}>
                <div style={{display:'flex', flexDirection:'column', gap:'4px'}}>
                  <span style={{fontSize:'0.7rem', fontWeight:'bold', color:'#64748b'}}>INICIO</span>
                  <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #e2e8f0'}}/>
                </div>
                <div style={{display:'flex', flexDirection:'column', gap:'4px'}}>
                  <span style={{fontSize:'0.7rem', fontWeight:'bold', color:'#64748b'}}>FIN</span>
                  <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={{padding:'8px', borderRadius:'8px', border:'1px solid #e2e8f0'}}/>
                </div>
            </div>
            <button onClick={publicarOfertas} disabled={cargando} style={btnNuevaSucursalCustom}>
                {cargando ? <Loader2 className="animate-spin" size={20}/> : <Sparkles size={20}/>}
                {cargando ? 'Publicando...' : 'Publicar Todo'}
            </button>
        </div>
      </div>

      <div style={{marginTop: '20px'}}>
        <h2 style={{...sidebarTitle, fontSize: '1.4rem', marginBottom: '20px'}}><Eye color="#1e293b" size={24}/> Productos Activos</h2>
        <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px'}}>
          {publicados.map(p => (
            <div key={p._id} style={{background: 'white', padding: '15px', borderRadius: '20px', border: '1px solid #e2e8f0', position: 'relative', boxShadow: '0 2px 4px rgba(0,0,0,0.02)'}}>
              <button onClick={() => eliminarOferta(p._id)} style={{position:'absolute', top:'10px', right:'10px', border:'none', background:'#fee2e2', color:'#ef4444', borderRadius:'50%', width:'28px', height:'28px', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center'}}><Trash size={14}/></button>
              <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_200,h_150,c_fill/v1/${p.publicId}`} style={{width:'100%', height:'110px', objectFit:'cover', borderRadius:'12px', marginBottom:'10px'}} alt={p.producto}/>
              <h4 style={{margin: '0', fontSize: '0.95rem', color: '#1e293b'}}>{p.producto}</h4>
              <div style={{display:'flex', gap:'8px', alignItems:'center', marginTop: '8px'}}>
                <span style={{fontWeight:'bold', color:'#e67e22'}}>${p.precioNuevo}</span>
                <span style={{textDecoration:'line-through', color:'#94a3b8', fontSize:'0.75rem'}}>${p.precioViejo}</span>
              </div>
              <p style={{fontSize:'0.75rem', color:'#64748b', marginTop:'4px'}}>Stock: {p.stock} | {p.categoria}</p>
            </div>
          ))}
          {publicados.length === 0 && <p style={{color: '#94a3b8', gridColumn: '1/-1', textAlign: 'center', padding: '40px'}}>Todavía no has publicado ofertas en esta sucursal.</p>}
        </div>
      </div>
    </div>
  );
};

export default GestionOfertas;
